  ('622e2cd8-c746-4535-83ac-ef7f0f4a877b', '30043bb0-fb2e-4bdd-96a0-1cee37a3c322', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, '¿Cuál de las siguientes fracciones es equivalente a 0,75?', '["1/2", "2/3", "3/4", "4/5"]'::jsonb, '2', '2026-07-19 03:03:05.926181+00', NULL, '0,75 = 75/100, que simplificado equivale a 3/4.', 'c0cec6e7-e9ed-4ed2-878f-3b388dbfe882', NULL, 'inicial', 'seleccion_multiple', '1', NULL, NULL, 'aprobado', '2026-07-19 03:03:05.926181+00', 'approved_for_exam', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, NULL, NULL, '{}'::uuid[], NULL, NULL),
  ('662f1958-0504-42ac-8183-2f9b6f2d5248', '30043bb0-fb2e-4bdd-96a0-1cee37a3c322', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, 'Un número irracional se ubica en la recta numérica entre dos números enteros consecutivos. ¿Qué par de números encierra a √10?', '["2 y 3", "3 y 4", "4 y 5", "5 y 6"]'::jsonb, '1', '2026-07-19 03:03:05.926181+00', NULL, '3² = 9 y 4² = 16; como 9 < 10 < 16, entonces 3 < √10 < 4.', 'c0cec6e7-e9ed-4ed2-878f-3b388dbfe882', NULL, 'avanzada', 'seleccion_multiple', '1', NULL, NULL, 'aprobado', '2026-07-19 03:03:05.926181+00', 'approved_for_exam', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, NULL, NULL, '{}'::uuid[], NULL, NULL),
